  const insets = useSafeAreaInsets();
  const { user, partner, isPremium } = useApp();
  const [showGate, setShowGate] = useState(false);

  if (!user || !partner) return null;

  const data = calculateCompatibility(
    user.birthDate,
    partner.birthDate,
