  "Why can't I move on?",
  "Do they still think about me?",
  "Why does this feel addictive?",
  "Why do we misunderstand each other?",
  "Should I reach out?",
];

function MessageBubble({ message }: { message: GuidanceMessage }) {
  const isUser = message.role === "user";
  return (
    <View style={[styles.bubbleRow, isUser ? styles.bubbleRowUser : styles.bubbleRowBot]}>
      {!isUser && (
        <View style={styles.botAvatar}>
          <Text style={styles.botAvatarText}>◉</Text>
        </View>
      )}
      <View style={[styles.bubble, isUser ? styles.bubbleUser : styles.bubbleBot]}>
        {isUser ? (
          <Text style={styles.bubbleUserText}>{message.text}</Text>
        ) : (
          <Text style={styles.bubbleBotText}>{message.text}</Text>
        )}
      </View>
    </View>
  );
}

function TypingIndicator() {
  const dot1 = useRef(new Animated.Value(0)).current;
  const dot2 = useRef(new Animated.Value(0)).current;
  const dot3 = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    const animateDot = (dot: Animated.Value, delay: number) =>
      Animated.loop(
        Animated.sequence([
          Animated.timing(dot, { toValue: 1, duration: 300, delay, useNativeDriver: true }),
          Animated.timing(dot, { toValue: 0, duration: 300, useNativeDriver: true }),
          Animated.delay(300),
        ])
      );
    animateDot(dot1, 0).start();
    animateDot(dot2, 200).start();
    animateDot(dot3, 400).start();
  }, []);

  return (
    <View style={styles.typingRow}>
      <View style={styles.botAvatar}>
        <Text style={styles.botAvatarText}>◉</Text>
      </View>
      <View style={styles.typingBubble}>
        {[dot1, dot2, dot3].map((dot, i) => (
          <Animated.View
            key={i}
            style={[
              styles.typingDot,
              { opacity: dot, transform: [{ scale: dot.interpolate({ inputRange: [0, 1], outputRange: [0.7, 1] }) }] },
            ]}
          />
        ))}
      </View>
    </View>
  );
}

import { Animated } from "react-native";

export default function GuidanceScreen() {
  const insets = useSafeAreaInsets();
  const { user, partner, guidanceMessages, addGuidanceMessage, isPremium } = useApp();
  const [input, setInput] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const flatListRef = useRef<FlatList>(null);
  const freeMessageCount = guidanceMessages.filter((m) => m.role === "user").length;
  const hitLimit = !isPremium && freeMessageCount >= 3;

  if (!user || !partner) return null;

  const sendMessage = async (text: string) => {
    if (!text.trim() || hitLimit) return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);

    const id = Date.now().toString() + Math.random().toString(36).substr(2, 5);
    const userMsg: GuidanceMessage = {
      id,
      role: "user",
      text: text.trim(),
      timestamp: Date.now(),
    };
    addGuidanceMessage(userMsg);
    setInput("");
    setIsTyping(true);

    await new Promise((r) => setTimeout(r, 1400 + Math.random() * 800));

    const responseText = getGuidanceResponse(text, partner.name, partner.relationshipType);
    const botMsg: GuidanceMessage = {
      id: id + "_bot",
      role: "assistant",
      text: responseText,
      timestamp: Date.now(),
    };
    addGuidanceMessage(botMsg);
    setIsTyping(false);
  };

  const allMessages = [...guidanceMessages];

  return (
    <LinearGradient colors={["#080611", "#0D0A1E"]} style={{ flex: 1 }}>
      <KeyboardAvoidingView
        behavior="padding"
        style={{ flex: 1 }}
        keyboardVerticalOffset={0}
      >
        {/* Header */}
        <View
          style={[
            styles.header,
            {
              paddingTop: insets.top + (Platform.OS === "web" ? 67 : 16),
            },
          ]}
        >
          <View>
            <Text style={styles.headerTitle}>Guidance</Text>
            <Text style={styles.headerSub}>Understanding {partner.name}</Text>
          </View>
          <View style={styles.headerTag}>
            <Text style={styles.headerTagText}>
              {isPremium ? "Unlimited" : `${3 - freeMessageCount} left`}
            </Text>
          </View>
        </View>

        {/* Messages */}
        <FlatList
          ref={flatListRef}
          data={allMessages}
          keyExtractor={(m) => m.id}
          style={{ flex: 1 }}
          contentContainerStyle={styles.messageList}
          showsVerticalScrollIndicator={false}
          onContentSizeChange={() => flatListRef.current?.scrollToEnd({ animated: true })}
          ListHeaderComponent={
            allMessages.length === 0 ? (
              <View style={styles.emptyState}>
                <Text style={styles.emptyIcon}>◉</Text>
                <Text style={styles.emptyTitle}>What's on your mind?</Text>
                <Text style={styles.emptySub}>
                  Ask anything about this connection. Everything you share stays private.
                </Text>
                <View style={styles.suggestionsGrid}>
                  {SUGGESTIONS.map((s, i) => (
                    <TouchableOpacity
                      key={i}
                      onPress={() => sendMessage(s)}
                      style={styles.suggestionChip}
                      activeOpacity={0.8}
                    >
                      <Text style={styles.suggestionText}>{s}</Text>
                    </TouchableOpacity>
                  ))}
                </View>
              </View>
            ) : null
          }
          ListFooterComponent={
            <>
              {isTyping && <TypingIndicator />}
              {hitLimit && (
                <View style={styles.limitBanner}>
                  <Text style={styles.limitText}>
                    Upgrade to Premium for unlimited guidance conversations
                  </Text>
                </View>
              )}
            </>
          }
          renderItem={({ item }) => <MessageBubble message={item} />}
        />

        {/* Input */}
        <View
          style={[
            styles.inputContainer,
            { paddingBottom: insets.bottom + (Platform.OS === "web" ? 34 : 12) },
          ]}
        >
          {!hitLimit && allMessages.length > 0 && (
            <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.chipScroll}>
              {SUGGESTIONS.slice(0, 3).map((s, i) => (
                <TouchableOpacity
                  key={i}
                  onPress={() => sendMessage(s)}
                  style={styles.inputChip}
                  activeOpacity={0.8}
                >
                  <Text style={styles.inputChipText}>{s}</Text>
                </TouchableOpacity>
              ))}
            </ScrollView>
          )}
          <View style={styles.inputRow}>
            <TextInput
              style={styles.input}
              value={input}
              onChangeText={setInput}
              placeholder={hitLimit ? "Upgrade for more" : "Ask about this connection..."}
              placeholderTextColor="rgba(240,235,248,0.25)"
              editable={!hitLimit}
              multiline
              maxLength={300}
            />
            <Pressable
              onPress={() => sendMessage(input)}
              disabled={!input.trim() || hitLimit}
              style={[styles.sendBtn, (!input.trim() || hitLimit) && { opacity: 0.4 }]}
            >
              <LinearGradient
                colors={["#E85C7A", "#B855E0"]}
                style={styles.sendGradient}
              >
                <Feather name="send" size={16} color="#fff" />
              </LinearGradient>
            </Pressable>
          </View>
        </View>
      </KeyboardAvoidingView>
    </LinearGradient>
  );
}

